"use strict";(self.webpackChunkspanish_app=self.webpackChunkspanish_app||[]).push([[6580],{6580:e=>{e.exports=JSON.parse('{"26":{"words":[{"spanish":"Por la lluvia","english":"Because of the rain"},{"spanish":"Por dos horas","english":"For two hours"},{"spanish":"Por correo electr\xf3nico","english":"By email"},{"spanish":"Por la ma\xf1ana","english":"In the morning"},{"spanish":"Por cinco d\xf3lares","english":"For five dollars"},{"spanish":"Caminar por el parque","english":"To walk through the park"},{"spanish":"Hecho por artesanos locales","english":"Made by local artisans"},{"spanish":"Dos veces por semana","english":"Twice per week"},{"spanish":"Gracias por venir","english":"Thanks for coming"},{"spanish":"Preguntar por el gerente","english":"To ask for the manager"},{"spanish":"Para ma\xf1ana","english":"By tomorrow"},{"spanish":"Para mi abuela","english":"For my grandmother"},{"spanish":"Para aprender","english":"In order to learn"},{"spanish":"Salir para Madrid","english":"To leave for Madrid"},{"spanish":"Trabajar para una ONG","english":"To work for an NGO"},{"spanish":"Para m\xed","english":"In my opinion"},{"spanish":"Esta mesa es para seis personas","english":"This table is for six people"},{"spanish":"Por error","english":"By mistake"},{"spanish":"Por costumbre","english":"Out of habit"},{"spanish":"Por internet","english":"Online"},{"spanish":"Por fin","english":"At last"},{"spanish":"Para siempre","english":"Forever"},{"spanish":"Por ciento","english":"Percent"},{"spanish":"Por persona","english":"Per person"},{"spanish":"Para el viernes","english":"By Friday"},{"spanish":"Por mi culpa","english":"Because of my fault"},{"spanish":"Para que descanses","english":"So that you can rest"},{"spanish":"Por todo el barrio","english":"All through the neighborhood"},{"spanish":"Por tel\xe9fono","english":"By phone"},{"spanish":"Para los clientes nuevos","english":"For new customers"},{"spanish":"Por el autor","english":"By the author"},{"spanish":"Para el sur","english":"Toward the south"},{"spanish":"Por ahora","english":"For now"},{"spanish":"Estar por salir","english":"To be about to leave"},{"spanish":"Para servirle","english":"At your service"},{"spanish":"Cambiarlo por otro","english":"To exchange it for another"},{"spanish":"Por suerte","english":"Fortunately"},{"spanish":"Para nada","english":"Not at all"},{"spanish":"Por la autopista","english":"Via the highway"},{"spanish":"Para dentro de un mes","english":"Within a month"},{"spanish":"Por razones m\xe9dicas","english":"For medical reasons"},{"spanish":"Para uso profesional","english":"For professional use"}],"conversations":[{"id":1,"topic":"Cambio de vuelo y preparativos de viaje","dialog":[{"speaker":"In\xe9s","spanish":"Salimos para Lima ma\xf1ana a las seis, pero la aerol\xednea cambi\xf3 el vuelo por la tormenta.","english":"We are leaving for Lima tomorrow at six, but the airline changed the flight because of the storm."},{"speaker":"Mateo","spanish":"Qu\xe9 mala suerte. \xbfNos reprogramaron para la noche o para el viernes?","english":"What bad luck. Did they reschedule us for tonight or for Friday?"},{"speaker":"In\xe9s","spanish":"Para esta noche, aunque tendremos que esperar en el aeropuerto por varias horas.","english":"For tonight, although we will have to wait at the airport for several hours."},{"speaker":"Mateo","spanish":"Entonces te mando los documentos por correo electr\xf3nico para que no los busques en la maleta.","english":"Then I will send you the documents by email so you do not have to look for them in the suitcase."},{"speaker":"In\xe9s","spanish":"Gracias. Tambi\xe9n necesito cambiar unos euros por soles antes de abordar.","english":"Thanks. I also need to exchange some euros for soles before boarding."},{"speaker":"Mateo","spanish":"Hazlo en la casa de cambio que est\xe1 por la puerta ocho; suele ser m\xe1s r\xe1pida.","english":"Do it at the exchange booth by gate eight; it is usually faster."}],"questions":[{"question":"\xbfPor qu\xe9 cambi\xf3 la aerol\xednea el vuelo?","options":["Por una huelga del personal","Por la tormenta","Por un error en el pasaporte","Por una aver\xeda en la maleta"],"answer":"Por la tormenta","answerIndex":1},{"question":"\xbfC\xf3mo piensa Mateo enviar los documentos?","options":["Por correo electr\xf3nico","Por mensajero","Por tel\xe9fono","Por taxi"],"answer":"Por correo electr\xf3nico","answerIndex":0},{"question":"\xbfQu\xe9 quiere cambiar In\xe9s antes de abordar?","options":["Unos d\xf3lares por euros","Unos euros por soles","Un asiento por otro","Una maleta por otra"],"answer":"Unos euros por soles","answerIndex":1}]},{"id":2,"topic":"Cambiar un regalo en una tienda","dialog":[{"speaker":"Clara","spanish":"Busco un regalo para mi abuela y quiero cambiar esta bufanda por algo m\xe1s ligero.","english":"I am looking for a gift for my grandmother and I want to exchange this scarf for something lighter."},{"speaker":"Leo","spanish":"Claro. \xbfLa compr\xf3 por internet o aqu\xed en la tienda?","english":"Of course. Did you buy it online or here in the store?"},{"speaker":"Clara","spanish":"La compr\xe9 aqu\xed por recomendaci\xf3n de mi hermana, pero es demasiado pesada para el clima de su ciudad.","english":"I bought it here on my sister\'s recommendation, but it is too heavy for the climate in her city."},{"speaker":"Leo","spanish":"En ese caso, le sugiero este pa\xf1uelo de seda. Es perfecto para viajar y est\xe1 en oferta por treinta d\xf3lares.","english":"In that case, I suggest this silk scarf. It is perfect for traveling and it is on sale for thirty dollars."},{"speaker":"Clara","spanish":"Me gusta. \xbfPuede envolverlo para regalo y enviarlo para el lunes?","english":"I like it. Can you wrap it as a gift and send it by Monday?"},{"speaker":"Leo","spanish":"S\xed, se lo enviamos por mensajer\xeda expr\xe9s para que llegue a tiempo.","english":"Yes, we will send it by express delivery so that it arrives on time."}],"questions":[{"question":"\xbfPara qui\xe9n busca Clara el regalo?","options":["Para su hermana","Para su jefa","Para su abuela","Para su vecina"],"answer":"Para su abuela","answerIndex":2},{"question":"\xbfPor qu\xe9 quiere cambiar la bufanda?","options":["Porque lleg\xf3 rota","Porque es demasiado pesada para ese clima","Porque la compr\xf3 por internet","Porque ya no tiene el recibo"],"answer":"Porque es demasiado pesada para ese clima","answerIndex":1},{"question":"\xbfPara cu\xe1ndo quiere Clara que env\xeden el nuevo regalo?","options":["Para el lunes","Para ma\xf1ana por la ma\xf1ana","Para dentro de un mes","Para el viernes siguiente"],"answer":"Para el lunes","answerIndex":0}]},{"id":3,"topic":"Entregas y plazos en la oficina","dialog":[{"speaker":"Sof\xeda","spanish":"Termin\xe9 el informe por la ma\xf1ana, pero todav\xeda falta una gr\xe1fica para la presentaci\xf3n del jueves.","english":"I finished the report in the morning, but a chart is still missing for Thursday\'s presentation."},{"speaker":"Bruno","spanish":"Env\xedamela por correo hoy, por favor, para que el equipo de dise\xf1o la revise antes de las cinco.","english":"Send it to me by email today, please, so that the design team can review it before five."},{"speaker":"Sof\xeda","spanish":"De acuerdo. Tambi\xe9n habl\xe9 por tel\xe9fono con el cliente y pidi\xf3 dos copias por persona para la reuni\xf3n.","english":"All right. I also spoke with the client by phone and he asked for two copies per person for the meeting."},{"speaker":"Bruno","spanish":"Perfecto. Ese proyecto es para una cadena de hoteles, as\xed que cuidemos cada detalle.","english":"Perfect. That project is for a hotel chain, so let us take care with every detail."},{"speaker":"Sof\xeda","spanish":"\xbfQuiere que vaya por la autopista o por el centro para entregar las muestras?","english":"Do you want me to go via the highway or through downtown to deliver the samples?"},{"speaker":"Bruno","spanish":"Ve por la autopista; llegar\xe1s m\xe1s r\xe1pido y volver\xe1s para el almuerzo.","english":"Go via the highway; you will arrive faster and be back for lunch."}],"questions":[{"question":"\xbfCu\xe1ndo termin\xf3 Sof\xeda el informe?","options":["Por la ma\xf1ana","Por la noche","Para el almuerzo","Para la pr\xf3xima semana"],"answer":"Por la ma\xf1ana","answerIndex":0},{"question":"\xbfCu\xe1ntas copias pidi\xf3 el cliente?","options":["Dos copias por persona","Una copia por oficina","Tres copias por mesa","Cinco copias para el gerente"],"answer":"Dos copias por persona","answerIndex":0},{"question":"\xbfQu\xe9 ruta le recomienda Bruno para entregar las muestras?","options":["Por el centro","Por la autopista","Por la costa","Por la estaci\xf3n de tren"],"answer":"Por la autopista","answerIndex":1}]},{"id":4,"topic":"Trabajo comunitario y organizaci\xf3n de voluntarios","dialog":[{"speaker":"Elena","spanish":"Trabajo para una fundaci\xf3n que reparte comida por todo el barrio los s\xe1bados.","english":"I work for a foundation that distributes food all through the neighborhood on Saturdays."},{"speaker":"Ra\xfal","spanish":"Qu\xe9 bien. A m\xed me eligieron por mi experiencia en log\xedstica para coordinar a los voluntarios.","english":"That is great. I was chosen because of my logistics experience to coordinate the volunteers."},{"speaker":"Elena","spanish":"Entonces, para m\xed, t\xfa eres la persona ideal para organizar la ruta.","english":"Then, in my opinion, you are the ideal person to organize the route."},{"speaker":"Ra\xfal","spanish":"Gracias. Los paquetes fueron preparados por estudiantes de la universidad y est\xe1n listos desde temprano.","english":"Thanks. The packages were prepared by university students and have been ready since early morning."},{"speaker":"Elena","spanish":"Perfecto. \xbfSalimos para el centro comunitario ahora o esperamos a Julia?","english":"Perfect. Do we leave for the community center now or do we wait for Julia?"},{"speaker":"Ra\xfal","spanish":"Esperemos diez minutos por cortes\xeda, pero despu\xe9s nos vamos para no llegar tarde.","english":"Let us wait ten minutes out of courtesy, but after that we should go so we are not late."}],"questions":[{"question":"\xbfQui\xe9n prepar\xf3 los paquetes?","options":["Los vecinos del barrio","Los estudiantes de la universidad","La gerente de la fundaci\xf3n","Los conductores del cami\xf3n"],"answer":"Los estudiantes de la universidad","answerIndex":1},{"question":"\xbfPor qu\xe9 eligieron a Ra\xfal para coordinar a los voluntarios?","options":["Por su experiencia en log\xedstica","Por su coche nuevo","Por su amistad con Julia","Por su trabajo en la universidad"],"answer":"Por su experiencia en log\xedstica","answerIndex":0},{"question":"\xbfPor qu\xe9 deciden esperar diez minutos antes de salir?","options":["Por cortes\xeda","Por la lluvia intensa","Por falta de mapas","Por una aver\xeda en el cami\xf3n"],"answer":"Por cortes\xeda","answerIndex":0}]}],"stories":[{"id":1,"title":"El informe para el viernes","sentences":[{"spanish":"Sof\xeda empez\xf3 a trabajar en el informe por la ma\xf1ana para terminarlo con calma antes de la reuni\xf3n.","english":"Sof\xeda started working on the report in the morning so she could finish it calmly before the meeting."},{"spanish":"Lo escribi\xf3 por tres horas seguidas y luego se lo mand\xf3 a Bruno por correo electr\xf3nico.","english":"She worked on it for three straight hours and then sent it to Bruno by email."},{"spanish":"El cliente quer\xeda las versiones impresas para el viernes, as\xed que el equipo revis\xf3 cada detalle con cuidado.","english":"The client wanted the printed versions by Friday, so the team reviewed every detail carefully."},{"spanish":"M\xe1s tarde, Sof\xeda sali\xf3 por la autopista para entregar unas muestras en un hotel del centro.","english":"Later, Sof\xeda left via the highway to deliver some samples to a downtown hotel."},{"spanish":"Volvi\xf3 cansada, pero contenta, porque todo hab\xeda salido seg\xfan el plan.","english":"She came back tired but happy because everything had gone according to plan."},{"spanish":"Para ella, ese d\xeda demostr\xf3 que la organizaci\xf3n vale tanto como el talento.","english":"For her, that day showed that organization matters just as much as talent."}]},{"id":2,"title":"Un regalo con intenci\xf3n","sentences":[{"spanish":"Clara quer\xeda comprar un regalo para su abuela, pero cambi\xf3 de idea por el clima c\xe1lido de su ciudad.","english":"Clara wanted to buy a gift for her grandmother, but she changed her mind because of the warm climate in her city."},{"spanish":"Hab\xeda elegido una bufanda por recomendaci\xf3n de su hermana, aunque no era la opci\xf3n m\xe1s pr\xe1ctica.","english":"She had chosen a scarf on her sister\'s recommendation, although it was not the most practical option."},{"spanish":"En la tienda encontr\xf3 un pa\xf1uelo de seda hecho por artesanos locales y decidi\xf3 cambiar la bufanda por ese detalle m\xe1s ligero.","english":"At the store, she found a silk scarf made by local artisans and decided to exchange the scarf for that lighter gift."},{"spanish":"Pag\xf3 por mensajer\xeda expr\xe9s para que el paquete llegara para el lunes sin falta.","english":"She paid for express delivery so that the package would arrive by Monday without fail."},{"spanish":"Cuando su abuela la llam\xf3 por tel\xe9fono, le dio las gracias por pensar en algo tan \xfatil.","english":"When her grandmother called her by phone, she thanked her for choosing something so useful."},{"spanish":"Clara sonri\xf3 porque, para ella, un buen regalo debe servir y emocionar al mismo tiempo.","english":"Clara smiled because, for her, a good gift should be useful and moving at the same time."}]},{"id":3,"title":"La brigada del barrio","sentences":[{"spanish":"Cada s\xe1bado, Elena sale para el centro comunitario antes de las ocho para organizar la distribuci\xf3n de comida.","english":"Every Saturday, Elena leaves for the community center before eight to organize the food distribution."},{"spanish":"Ra\xfal fue elegido por su experiencia en log\xedstica y por su paciencia con los voluntarios nuevos.","english":"Ra\xfal was chosen because of his logistics experience and his patience with the new volunteers."},{"spanish":"Los paquetes, preparados por estudiantes universitarios, llegan clasificados por zona y por n\xfamero de familias.","english":"The packages, prepared by university students, arrive sorted by zone and by number of families."},{"spanish":"Luego el equipo recorre el barrio por varias horas para entregar todo antes del mediod\xeda.","english":"Then the team goes through the neighborhood for several hours to deliver everything before noon."},{"spanish":"Para muchos vecinos, esa visita semanal es importante no solo por la comida, sino tambi\xe9n por la conversaci\xf3n.","english":"For many neighbors, that weekly visit matters not only because of the food but also because of the conversation."},{"spanish":"Al terminar, Elena siempre agradece a todos por su tiempo y por su compromiso.","english":"At the end, Elena always thanks everyone for their time and commitment."}]}],"speaking":{"title":"Pr\xe1ctica oral de por y para","description":"Contrasta por y para al hablar de causa, prop\xf3sito, plazos, intercambio, duraci\xf3n y destino.","questions_and_answers":[{"question":{"spanish":"Di en espa\xf1ol: I work for an international company.","english":"Say in Spanish: I work for an international company."},"answer":{"spanish":"Trabajo para una empresa internacional.","english":"I work for an international company."}},{"question":{"spanish":"Di en espa\xf1ol: I called you by phone last night.","english":"Say in Spanish: I called you by phone last night."},"answer":{"spanish":"Te llam\xe9 por tel\xe9fono anoche.","english":"I called you by phone last night."}},{"question":{"spanish":"Di en espa\xf1ol: We are leaving for Seville tomorrow morning.","english":"Say in Spanish: We are leaving for Seville tomorrow morning."},"answer":{"spanish":"Salimos para Sevilla ma\xf1ana temprano.","english":"We are leaving for Seville tomorrow morning."}},{"question":{"spanish":"Di en espa\xf1ol: Thanks for helping me with the move.","english":"Say in Spanish: Thanks for helping me with the move."},"answer":{"spanish":"Gracias por ayudarme con la mudanza.","english":"Thanks for helping me with the move."}},{"question":{"spanish":"Di en espa\xf1ol: I need the report by Friday.","english":"Say in Spanish: I need the report by Friday."},"answer":{"spanish":"Necesito el reporte para el viernes.","english":"I need the report by Friday."}},{"question":{"spanish":"Di en espa\xf1ol: We walked through the forest for one hour.","english":"Say in Spanish: We walked through the forest for one hour."},"answer":{"spanish":"Caminamos por el bosque durante una hora.","english":"We walked through the forest for one hour."}},{"question":{"spanish":"Di en espa\xf1ol: I bought these flowers for my mother.","english":"Say in Spanish: I bought these flowers for my mother."},"answer":{"spanish":"Compr\xe9 estas flores para mi madre.","english":"I bought these flowers for my mother."}},{"question":{"spanish":"Di en espa\xf1ol: I exchanged my seat for one by the window.","english":"Say in Spanish: I exchanged my seat for one by the window."},"answer":{"spanish":"Cambi\xe9 mi asiento por uno junto a la ventana.","english":"I exchanged my seat for one by the window."}},{"question":{"spanish":"Di en espa\xf1ol: I did it out of curiosity, not out of obligation.","english":"Say in Spanish: I did it out of curiosity, not out of obligation."},"answer":{"spanish":"Lo hice por curiosidad, no por obligaci\xf3n.","english":"I did it out of curiosity, not out of obligation."}},{"question":{"spanish":"Di en espa\xf1ol: This gift is for you.","english":"Say in Spanish: This gift is for you."},"answer":{"spanish":"Este regalo es para ti.","english":"This gift is for you."}},{"question":{"spanish":"Di en espa\xf1ol: The bridge was designed by a Chilean engineer.","english":"Say in Spanish: The bridge was designed by a Chilean engineer."},"answer":{"spanish":"El puente fue dise\xf1ado por una ingeniera chilena.","english":"The bridge was designed by a Chilean engineer."}},{"question":{"spanish":"Di en espa\xf1ol: We studied for three hours before the exam.","english":"Say in Spanish: We studied for three hours before the exam."},"answer":{"spanish":"Estudiamos por tres horas antes del examen.","english":"We studied for three hours before the exam."}},{"question":{"spanish":"Di en espa\xf1ol: I am sending you the contract by email.","english":"Say in Spanish: I am sending you the contract by email."},"answer":{"spanish":"Te env\xedo el contrato por correo electr\xf3nico.","english":"I am sending you the contract by email."}},{"question":{"spanish":"Di en espa\xf1ol: In my opinion, that solution is the fairest.","english":"Say in Spanish: In my opinion, that solution is the fairest."},"answer":{"spanish":"Para m\xed, esa soluci\xf3n es la m\xe1s justa.","english":"In my opinion, that solution is the fairest."}},{"question":{"spanish":"Di en espa\xf1ol: We need ten chairs for the meeting.","english":"Say in Spanish: We need ten chairs for the meeting."},"answer":{"spanish":"Necesitamos diez sillas para la reuni\xf3n.","english":"We need ten chairs for the meeting."}},{"question":{"spanish":"Di en espa\xf1ol: We went through the market before going home.","english":"Say in Spanish: We went through the market before going home."},"answer":{"spanish":"Pasamos por el mercado antes de volver a casa.","english":"We went through the market before going home."}},{"question":{"spanish":"Di en espa\xf1ol: I work here to pay for my studies.","english":"Say in Spanish: I work here to pay for my studies."},"answer":{"spanish":"Trabajo aqu\xed para pagar mis estudios.","english":"I work here to pay for my studies."}},{"question":{"spanish":"Di en espa\xf1ol: They sold the bicycle for two hundred euros.","english":"Say in Spanish: They sold the bicycle for two hundred euros."},"answer":{"spanish":"Vendieron la bicicleta por doscientos euros.","english":"They sold the bicycle for two hundred euros."}},{"question":{"spanish":"Di en espa\xf1ol: Leave home now so that you arrive on time.","english":"Say in Spanish: Leave home now so that you arrive on time."},"answer":{"spanish":"Sal de casa ahora para llegar a tiempo.","english":"Leave home now so that you arrive on time."}},{"question":{"spanish":"Di en espa\xf1ol: We have meetings twice per week.","english":"Say in Spanish: We have meetings twice per week."},"answer":{"spanish":"Hacemos reuniones dos veces por semana.","english":"We have meetings twice per week."}}]}}}')}}]);